/* ── CSV parser ── */
function parseCSV(text) {
  const lines = text.split("\n").filter(l => l.trim());
  if (lines.length < 2) return [];
  const parseLine = line => {
    const r=[]; let cur="",q=false;
    for(let i=0;i<line.length;i++){
      if(line[i]==='"'){if(q&&line[i+1]==='"'){cur+='"';i++;}else q=!q;}
      else if(line[i]===','&&!q){r.push(cur.trim());cur="";}
      else cur+=line[i];
    }
    r.push(cur.trim()); return r;
  };
  const hdrs = parseLine(lines[0]).map(h=>h.replace(/^"|"$/g,"").trim());
  return lines.slice(1).map(line=>{
    const vals=parseLine(line),obj={};
    hdrs.forEach((h,i)=>{let v=(vals[i]||"").replace(/^"|"$/g,"").trim();if(v==="#ERROR!"||v==="null")v="";obj[h]=v;});
    if(!obj.name&&obj.nameKo)obj.name=obj.nameKo;
    return obj;
  }).filter(r=>r.name&&r.name.trim());
}


