async function fetchExhibition() {
  try {
    const url = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/gviz/tq?tqx=out:csv&sheet=Exhibition`;
    const res = await fetch(url, { cache: "no-cache" });
    if (!res.ok) return null;
    const text = await res.text();
    if (text.includes("<!DOCTYPE") || text.includes("<html")) return null;
    const lines = text.split("\n").filter(l => l.trim());
    if (lines.length < 2) return null;
    const parseLine = (line) => {
      const r=[]; let cur="",q=false;
      for(let i=0;i<line.length;i++){
        if(line[i]==='"'){if(q&&line[i+1]==='"'){cur+='"';i++;}else q=!q;}
        else if(line[i]===","&&!q){r.push(cur.trim());cur="";}
        else cur+=line[i];
      }
      r.push(cur.trim()); return r;
    };
    const headers = parseLine(lines[0]).map(h=>h.replace(/^"|"$/g,"").trim());
    const vals = parseLine(lines[1]);
    const obj = {};
    headers.forEach((h,i)=>{ obj[h] = (vals[i]||"").replace(/^"|"$/g,"").trim(); });
    return obj.title ? obj : null;
  } catch(e) { return null; }
}

async function fetchSheet(name) {
  try {
    const res = await fetch(`https://docs.google.com/spreadsheets/d/${SHEET_ID}/gviz/tq?tqx=out:csv&sheet=${encodeURIComponent(name)}`,{cache:"no-cache"});
    if(!res.ok) return [];
    const text = await res.text();
    if(text.includes("<!DOCTYPE")||text.includes("<html")) return [];
    const rows = parseCSV(text);
    rows.sort((a,b)=>{ const sa=parseInt(a.star)||0,sb=parseInt(b.star)||0; return sb!==sa?sb-sa:a.name.localeCompare(b.name); });
    return rows;
  } catch{ return []; }
}

/* ── Place card ── */
function PlaceCard({ place, idx, open, onToggle }) {
  const stars = place.star ? "★".repeat(Math.min(parseInt(place.star)||0, 3)) : "";
  return (
    <div className={`pc${open?" open":""}`} onClick={onToggle}>
      <div className="pc-row">
        <div className="pc-left">
          <span className="pc-n">{String(idx+1).padStart(2,"0")}</span>
          {stars && <span className="pc-stars">{stars}</span>}
        </div>
        <div className="pc-divider"/>
        <div className="pc-body">
          <span className="pc-name">{place.name}</span>
          {(place.type || place.nameKo) && (
            <div className="pc-sub">
              {place.type && <span>{place.type}</span>}
              {place.type && place.nameKo && <span> · </span>}
              {place.nameKo && <span>{place.nameKo}</span>}
            </div>
          )}
          {place.comment && <p className="pc-comment">{place.comment}</p>}
        </div>
        <span className="pc-tog">{open?"–":"+"}</span>
      </div>
      {open && (
        <div className="pc-detail" onClick={e=>e.stopPropagation()}>
          {place.note && <p className="pd-note">{place.note}</p>}
          <div className="pd-grid">
            {place.menu&&<div className="pd-row"><span className="pd-lbl">Try</span><span className="pd-val italic">{place.menu}</span></div>}
            {(place.addressEn||place.addressKo)&&<div className="pd-row"><span className="pd-lbl">Address</span><span className="pd-val">{place.addressEn}{place.addressKo&&<span className="pd-ko"> {place.addressKo}</span>}</span></div>}
            {place.hours&&<div className="pd-row"><span className="pd-lbl">Hours</span><span className="pd-val">{place.hours}</span></div>}
            {(place.map||place.website)&&(
              <div className="pd-row">
                <span className="pd-lbl">Links</span>
                <span className="pd-val">
                  {place.map&&<a href={place.map} target="_blank" rel="noopener noreferrer" className="pd-link" onClick={e=>e.stopPropagation()}>Maps ↗</a>}
                  {place.website&&<a href={place.website} target="_blank" rel="noopener noreferrer" className="pd-link" onClick={e=>e.stopPropagation()}>Site ↗</a>}
                </span>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

